con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

//Läs in mockens data.xml
import se.skl.rivta.tksupport.soapui.datasource.XmlDataReaderMock
import com.eviware.soapui.support.GroovyUtils
def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReaderMock(context, dataFile)
source.load()

synchronized(mockRequest.context.mockService){
	mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation)

	context.message = getSchemaErrorMessage() //?: getSchematronErrorMessage()
	if (context.message) {
		return "SoapFault"
	}
	if (mockRequest.requestHeaders.containsKey('x-mock-response')) {
		def responseName = mockRequest.requestHeaders['x-mock-response'][0]
		log.debug("responseName: ${responseName}")
		return responseName
	}
	return "Response OK"
}

def getSchemaErrorMessage() {
    log.info "Schema validation started"
     return  mh.getSchemaErrorsInRequest()
}

def getSchematronErrorMessage() {
    log.info "Schematron validation started"
    def groovyUtils = new com.eviware.soapui.support.GroovyUtils(context)
    def file = new File(groovyUtils.projectPath + "/constraints.xml")
    return mh.getSchematronErrorsInRequest(file)
}
